INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '26a41594-71d2-4498-b30c-0509d2b05f6b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Rails JWT Auth — Validation, Decode, and Before-Action Middleware$escape$,
  $escape$Rails has no built-in JWT support, so most apps reach for the `jwt` gem alongside a custom concern. The cleanest pattern: decode and validate in a reusable `Authenticatable` concern, mount it via `before_action :authenticate_user!` in `ApplicationController`, and skip it per-controller with `skip_before_action`.

Decode inside a `rescue` block — `JWT::DecodeError` covers expired tokens, bad signatures, and malformed payloads. Always pass `algorithms: ['HS256']` explicitly; omitting it allows the `none` algorithm attack.

Store the secret in `Rails.application.credentials.jwt_secret` (not an env var read at class load time) so it rotates cleanly per environment. For session-like behavior without cookies, stash the decoded payload in `Current.user` via `ActiveSupport::CurrentAttributes` — this gives you thread-safe, request-scoped access anywhere in the stack without passing the user object through every method call. Avoid storing JWTs in Rails session (`session[]`); that defeats statelessness and inflates cookie size.$escape$,
  $escape$# app/controllers/concerns/authenticatable.rb
module Authenticatable
  extend ActiveSupport::Concern

  included do
    before_action :authenticate_user!
  end

  private

  def authenticate_user!
    token = request.headers["Authorization"]&.split(" ")&.last
    payload, = JWT.decode(
      token,
      Rails.application.credentials.jwt_secret!,
      true,
      algorithms: ["HS256"]
    )
    Current.user = User.find(payload["sub"])
  rescue JWT::DecodeError
    render json: { error: "Unauthorized" }, status: :unauthorized
  end
end$escape$,
  $escape$ruby$escape$,
