INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '604fd146-c282-4364-8cb2-f7b76ed63962',
  '00000000-0000-0000-0000-000000000001',
  $escape$Rails Testing — Unit vs Integration, HTTP Mocking, and Database Strategy$escape$,
  $escape$Rails unit tests (model specs) hit the database by default — unlike most frameworks. Use `build_stubbed` from FactoryBot to avoid DB writes entirely when testing pure logic like validations or instance methods. Integration tests (request specs) should hit a real test database; avoid mocking ActiveRecord here since you want the full stack exercised.

For external HTTP calls, use WebMock or VCR. WebMock lets you stub at the net layer — `stub_request(:get, /api.github.com/)` intercepts before any socket opens. VCR records real responses into cassettes, ideal for third-party APIs with complex payloads.

Database strategy: use `database_cleaner-active_record` with `truncation` for system/feature specs and `transaction` for unit/request specs. Transaction rollback is 10–20x faster but breaks specs that spawn threads (Capybara, Sidekiq inline). Set `DatabaseCleaner.strategy = :transaction` globally, override to `:truncation` per spec tag with `js: true`. Keep your test.rb database config pointing to a separate DB — never share with development.$escape$,
  $escape$# spec/support/database_cleaner.rb
RSpec.configure do |config|
  config.before(:suite) { DatabaseCleaner.clean_with(:truncation) }

  config.before(:each) { DatabaseCleaner.strategy = :transaction }
  config.before(:each, js: true) { DatabaseCleaner.strategy = :truncation }

  config.before(:each) { DatabaseCleaner.start }
  config.after(:each)  { DatabaseCleaner.clean }
end

# WebMock stub example
stub_request(:get, "https://api.github.com/users/octocat")
  .to_return(status: 200, body: { login: "octocat" }.to_json, headers: { "Content-Type" => "application/json" })$escape$,
  $escape$ruby$escape$,
