INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd4b2e15c-352b-4417-9aa2-2e10a20d8372',
  '00000000-0000-0000-0000-000000000001',
  $escape$Rails Security Essentials — CORS, Rate Limiting, Headers, and Injection Prevention$escape$,
  $escape$Rails ships with solid defaults, but production apps need deliberate hardening. For CORS, use the `rack-cors` gem: configure `config/initializers/cors.rb` to whitelist specific origins rather than `'*'`. Pair it with `ActionDispatch::SSL` middleware and `config.force_ssl = true` in production.

For rate limiting, `rack-attack` is the Rails standard. Define throttles in an initializer — `Rack::Attack.throttle('api/ip', limit: 100, period: 1.minute)` — and mount it in `config/application.rb` with `config.middleware.use Rack::Attack`.

Security headers are handled by the `secure_headers` gem. Set `X-Frame-Options`, `X-Content-Type-Options`, `Strict-Transport-Security`, and a tight `Content-Security-Policy` in one initializer block.

For injection prevention, Rails ActiveRecord parameterizes queries automatically — never interpolate user input into `where` strings. Use `sanitize` and `html_escape` (aliased as `h`) in views. For shell calls, avoid `system()` with user input; use `Open3.capture2e` with array args to prevent shell injection.$escape$,
  $escape$# config/initializers/rack_attack.rb
Rack::Attack.throttle('req/ip', limit: 100, period: 1.minute) do |req|
  req.ip unless req.path.start_with?('/assets')
end

Rack::Attack.throttle('logins/email', limit: 5, period: 20.seconds) do |req|
  req.params['email']&.downcase if req.path == '/users/sign_in' && req.post?
end

Rack::Attack.blocklist('block bad actors') do |req|
  Rack::Attack::Allow2Ban.filter(req.ip, maxretry: 10, findtime: 1.minute, bantime: 1.hour) do
    req.path == '/users/sign_in' && req.post?
  end
end$escape$,
  $escape$ruby$escape$,
