INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '41fa316a-4d20-4ce3-98fd-a3a89fd5d8f3',
  '00000000-0000-0000-0000-000000000001',
  $escape$Rails API Versioning — Namespaces, Constraints, and rswag Docs$escape$,
  $escape$Rails' routing DSL makes API versioning clean with nested namespaces. Use `namespace :v1` to scope both routes and controllers under `Api::V1`, keeping your versions fully isolated. For header-based versioning (Accept: application/vnd.myapp.v2+json), define a custom route constraint class that reads `request.headers['Accept']` and matches on the version string — mount it before the default namespace so it intercepts first.

Inherit from `ActionController::API` instead of `ApplicationController` in your API base class to strip middleware like cookie sessions and view rendering — this alone cuts request overhead measurably.

For OpenAPI generation, `rswag` integrates directly with RSpec: you write request specs with a `swagger_helper`, annotate endpoints using its DSL (`parameter`, `response`, `schema`), then run `rails rswag:specs:swaggerize` to emit a `swagger.json`. This keeps docs co-located with tests and forces them to stay accurate. Pair with `rswag-ui` to mount Swagger UI at `/api-docs` — zero extra infrastructure needed.$escape$,
  $escape$# config/routes.rb
Rails.application.routes.draw do
  namespace :api do
    namespace :v1 do
      resources :posts, only: [:index, :show, :create]
    end

    namespace :v2 do
      resources :posts, only: [:index, :show, :create]
    end
  end
end

# app/controllers/api/base_controller.rb
module Api
  class BaseController < ActionController::API
    before_action :authenticate_request!
  end
end

# app/controllers/api/v1/posts_controller.rb
module Api
  module V1
    class PostsController < Api::BaseController
      def index
        render json: Post.all, status: :ok
      end
    end
  end
end$escape$,
