INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '15e36bf7-b204-4db7-979b-b1af42384be4',
  '00000000-0000-0000-0000-000000000001',
  $escape$Rails Structured Logging — Correlation IDs and Request Middleware$escape$,
  $escape$Rails' default logger emits plain-text lines — useless in production when you need to trace a single request across dozens of log entries. Switch to `semantic_logger` or configure `ActiveSupport::Logger` with `broadcast` to emit JSON. The real unlock is correlation IDs: generate a UUID per request in a `before_action` and store it in `Current` (ActiveSupport::CurrentAttributes), then thread it through every log call automatically via a custom log formatter.

Mount a middleware to inject the ID early — before the router — so even 404s and Rack-level errors carry it. Read `X-Request-Id` from the incoming headers first; fall back to `SecureRandom.uuid`. This lets upstream services (load balancers, APMs like Datadog or Honeybadger) correlate distributed traces.

Tag log lines with `Rails.logger.tagged(Current.request_id)` or set `config.log_tags` in `application.rb` to `[:request_id]` — Rails will prepend it to every `ActiveSupport::TaggedLogging` entry automatically. Pair with `lograge` to collapse noisy ActionController multi-line output into a single structured JSON object per request.$escape$,
  $escape$# config/application.rb
config.log_tags = [:request_id]
config.logger = ActiveSupport::Logger.new(STDOUT)
  .then { ActiveSupport::TaggedLogging.new(_1) }

# app/middleware/correlation_id_middleware.rb
class CorrelationIdMiddleware
  def initialize(app) = @app = app

  def call(env)
    id = env["HTTP_X_REQUEST_ID"] || SecureRandom.uuid
    Current.request_id = id
    env["action_dispatch.request_id"] = id
    @app.call(env)
  end
end

# config/application.rb
config.middleware.insert_before Rails::Rack::Logger, CorrelationIdMiddleware$escape$,
